// Assemble the final structured markdown research document (frontmatter + agent
// output) and a filename. Reads the AI Agent output ($json.output).
const meta = $('Fetch Transcript').first().json;
const body = $input.first().json; // AI Agent response

let text = '';
try {
  text = String(body.output != null ? body.output : (body.text || '')).trim();
} catch (e) { text = ''; }
if (!text) { throw new Error('Agent returned no text'); }

const title = meta.title || 'Untitled';
const channel = meta.channel || '';
const url = meta.url || '';
const videoId = meta.video_id || '';

function slugify(s) {
  return (s || 'note').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').substring(0, 80) || 'note';
}
const q = function (s) { return String(s || '').replace(/"/g, '\\"'); };
const date = new Date().toISOString().split('T')[0];
const filename = slugify(title) + '-' + videoId + '.md';

const frontmatter =
  '---\n' +
  'title: "' + q(title) + '"\n' +
  'source: ' + url + '\n' +
  'channel: "' + q(channel) + '"\n' +
  'video_id: ' + videoId + '\n' +
  'captured: ' + date + '\n' +
  'type: youtube-research\n' +
  '---\n\n';

const markdown = frontmatter + '# ' + title + '\n\n' + text + '\n';

return [{ json: { filename: filename, markdown: markdown, title: title, video_id: videoId, source: url } }];
